def get_next_num(directory):
    existing = list(directory.glob("quiz_*_pt.json"))
    nums = []
    for f in existing:
        try:
            nums.append(int(f.stem.split("_")[1]))
        except:
            pass
    return max(nums) + 1 if nums else 1

dir1 = Path("static/quizzes/iso27001_li/fundamentals_isms")
dir1.mkdir(parents=True, exist_ok=True)
num1 = get_next_num(dir1)
out1 = {
    "cert_id": "iso27001_li",
    "domain_id": "fundamentals_isms",
    "quiz_num": num1,
    "domain_name": "Fundamentos e Gestão de ISMS",
    "cert_name": "ISO 27001 Lead Implementer",
    "lang": "pt",
    "questions": questions
}
path1 = dir1 / f"quiz_{num1:03d}_pt.json"
path1.write_text(json.dumps(out1, ensure_ascii=False, indent=2), encoding="utf-8")
print(f"OK - {len(questions)} questoes (ISO 27001 LI Fundamentos) salvas em {path1}")
